     3→import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
     4→import { eventSelectContent } from '~/constants/functions';
     5→import { Dimensions } from 'react-native';
     6→import { FilterOption } from '../../../redux/ducks/points';
     7→import { TYPE_LABELS, TransactionType} from '../../../services/models';
     8→
     9→interface FilterGroup {
    10→  label: string;
    11→  options: FilterOption[];
    12→}
    13→
    14→interface FiltersBottomSheetProps {
    15→  modalizeRef: React.RefObject<PropsModalizeRef>;
    16→  filterGroups: FilterGroup[];
    17→  onApplyFilters: (filters: any) => void;
    18→  initialFilters?: any;
    19→}
    20→
    21→interface MemoizedFilterGroupProps {
    22→  group: FilterGroup;
    23→  groupIndex: number;
    24→  selectedIndex: number | undefined;
    25→  filterItems: Array<{ id: number; title: string }>;
    26→  onFilterChange: (groupIndex: number, options: FilterOption[]) => (item: any, index: number | number[]) => void;
    27→}
    28→
    29→const MemoizedFilterGroup = React.memo<MemoizedFilterGroupProps>(({ 
    30→  group, 
    31→  groupIndex, 
    32→  selectedIndex, 
    33→  filterItems,
    34→  onFilterChange 
    35→}) => {
    36→  const filterChangeHandler = onFilterChange(groupIndex, group.options);
    37→  
    38→  return (
    39→    <Box>
    40→      <Text 
    41→        type="paragraphXL" 
    42→        color="INTENSE_COLOR_05" 
    43→        mt={groupIndex === 0 ? "xxxs" : "xxs"} 
    44→        ml="small" 
    45→        mb="xxxs"
    46→      >
    47→        {group.label}
    48→      </Text>
    49→
    50→      <ChooseButton
    51→        items={filterItems}
    52→        type="select"
    53→        ml="small"
    54→        numColumns={3}
    55→        selectMultipleItems={false}
    56→        defaultOption={selectedIndex}
    57→        onPress={filterChangeHandler}
    58→      />
    59→    </Box>
    60→  );
    61→});
    62→
    63→const FiltersBottomSheet: FC<FiltersBottomSheetProps> = ({
    64→  modalizeRef,
    65→  filterGroups,
    66→  onApplyFilters,
    67→  initialFilters = {},
    68→}) => {
    69→  const [selectedFilters, setSelectedFilters] = useState<Record<number, any>>(initialFilters);
    70→  
    71→  const screenWidth = useMemo(() => Dimensions.get('window').width, []);
    72→
    73→  useEffect(() => {
    74→    setSelectedFilters(initialFilters);
    75→  }, [initialFilters]);
    76→
    77→  const filterItemsMap = useMemo(() => {
    78→    return filterGroups.map(group => 
    79→      group.options.map((option, idx) => ({
    80→        id: idx,
    81→        title: option.label,
    82→      }))
    83→    );
    84→  }, [filterGroups]);
    85→
    86→  const selectedIndices = useMemo(() => {
    87→    return filterGroups.map((group, groupIndex) => {
    88→      const selectedValue = selectedFilters[groupIndex];
    89→      
    90→      if (selectedValue === undefined) {
    91→        return undefined;
    92→      }
    93→      
    94→      const index = group.options.findIndex(opt => opt.value === selectedValue);
    95→      return index >= 0 ? index : undefined;
    96→    });
    97→  }, [filterGroups, selectedFilters]);
    98→
    99→  const handleFilterChange = useCallback((groupIndex: number, options: FilterOption[]) => {
   100→    return (item: any, index: number | number[]) => {
   101→      const selectedIndex = Array.isArray(index) ? index[0] : index;
   102→      if (selectedIndex !== undefined && selectedIndex >= 0) {
   103→        const value = options[selectedIndex].value;
   104→
   105→        setSelectedFilters(prev => {
   106→          const currentValue = prev[groupIndex];
   107→          const newValue = currentValue === value ? undefined : value;
   108→          return { ...prev, [groupIndex]: newValue };
   109→        });
   110→      }
   111→    };
   112→  }, []);
   113→
   114→  const handleClear = useCallback(() => {
   115→    modalizeRef.current?.close?.();
   116→    
   117→    setTimeout(() => {
   118→      setSelectedFilters({});
   119→      onApplyFilters({});
   120→    }, 100);
   121→  }, [onApplyFilters, modalizeRef]);
   122→
   123→  const handleApply = useCallback(() => {
   124→    const filtersToApply = selectedFilters;
   125→    const period = filtersToApply[0];
   126→    const type = filtersToApply[1];
   127→    
   128→    const contentIdParts = ['filtrar'];
